queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
SELECT ?v WHERE { { SELECT (MIN(?a) AS ?v) WHERE { ?x a :Age_Rating ; p:ageMinimum ?a } } UNION { SELECT (MIN(?s) AS ?v) WHERE { ?y a :Critical_Rating ; p:score ?s } } }

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?score WHERE {
  ?critical_rating a :Critical_Rating .
  ?tv_show a :Tv_Show .
  ?tv_show p:hasCritical_Rating ?critical_rating .
  ?critical_rating p:score ?score .
  ?tv_show p:title ?title_f .
  FILTER(STR(?title_f) = "Breaking Bad")
} }
  full: { SELECT DISTINCT ?o0 WHERE {
  {
    ?age_rating a :Age_Rating .
    ?tv_show a :Tv_Show .
    ?tv_show p:hasAge_Rating ?age_rating .
    ?age_rating p:ageMinimum ?ageminimum .
    ?tv_show p:title ?title_f .
    FILTER(STR(?title_f) = "Breaking Bad")
    BIND(?ageminimum AS ?o0)
  }
  UNION
  {
    ?critical_rating a :Critical_Rating .
    ?tv_show a :Tv_Show .
    ?tv_show p:hasCritical_Rating ?critical_rating .
    ?critical_rating p:score ?score .
    ?tv_show p:title ?title_f .
    FILTER(STR(?title_f) = "Breaking Bad")
    BIND(?score AS ?o0)
  }
} }
  component_2: { SELECT ?ageminimum WHERE {
  ?age_rating a :Age_Rating .
  ?tv_show a :Tv_Show .
  ?tv_show p:hasAge_Rating ?age_rating .
  ?age_rating p:ageMinimum ?ageminimum .
  ?tv_show p:title ?title_f .
  FILTER(STR(?title_f) = "Breaking Bad")
} }
}

